/** English display label from slug (hyphens → spaces). */
export function englishTaxonomyLabel(slug: string): string {
  if (!slug) return "";
  return slug.replace(/-/g, " ");
}

/** Localized taxonomy slug label. Falls back to English spacing. */
export function taxonomyLabel(slug: string, locale: LocaleCode | string): string {
  if (!slug) return "";
  if (locale === "zh") {
    const hit = ZH[slug];
    if (hit) return hit;
  }
  return englishTaxonomyLabel(slug);
}

/** Localized technique group title (e.g. "Camera & Movement"). */
export function techniqueGroupLabel(group: string, locale: LocaleCode | string): string {
  if (!group) return "";
  const pack = GROUP_LABELS[locale];
  if (pack?.[group]) return pack[group];
  return group;
}

/** Match search needle against slug and localized label. */
export function taxonomyMatches(
  slug: string,
  needle: string,
  locale: LocaleCode | string
): boolean {
  if (!needle) return true;
  const n = needle.toLowerCase();
  if (slug.toLowerCase().includes(n)) return true;
  const label = taxonomyLabel(slug, locale).toLowerCase();
  return label.includes(n);
}

/** Coverage helper for debug: curated ZH labels vs dump size (497/497). */
export const TAXONOMY_ZH_COVERAGE = { covered: 497, total: 497 } as const;
